 1→import { randomUUID } from "node:crypto";
 2→import { runWithRequestContext } from "../request-context";
 3→import { jsonError, withRequestIdHeader } from "./response";
 4→import { elapsedMs, logDebug, logError, logInfo } from "./observability";
 5→
 6→export type RouteRequest = Request & {
 7→  params: Record<string, string>;
 8→};
 9→
10→export type RouteHandler = (request: RouteRequest) => Response | Promise<Response>;
11→
12→export function withRequestLogging(route: string, method: string, handler: RouteHandler): RouteHandler {
13→  return async (request: RouteRequest) => {
14→    const startedAt = performance.now();
15→    const headerValue = request.headers.get("x-request-id")?.trim();
16→    const requestId = headerValue && headerValue.length > 0 ? headerValue : randomUUID();
17→    const path = new URL(request.url).pathname;
18→
19→    return runWithRequestContext(
20→      {
21→        requestId,
22→        method,
23→        route,
24→        path,
25→      },
26→      async () => {
27→        logDebug("http.request.received", "HTTP request received");
28→
29→        try {
30→          const response = await handler(request);
31→          const responseWithRequestId = withRequestIdHeader(response, requestId);
32→          logInfo("http.request.completed", "HTTP request completed", {
33→            statusCode: responseWithRequestId.status,
34→            durationMs: elapsedMs(startedAt),
35→          });
36→          return responseWithRequestId;
37→        } catch (error) {
38→          logError("http.request.failed", "HTTP request failed", error, {
39→            durationMs: elapsedMs(startedAt),
40→          });
41→          const fallback = jsonError("internal server error", 500);
42→          return withRequestIdHeader(fallback, requestId);
43→        }
44→      },
45→    );
46→  };
47→}
48→

 1→import { getRequestLogger, serializeError } from "../logging";
 2→
 3→export function logDebug(event: string, message: string, meta?: Record<string, unknown>): void {
 4→  getRequestLogger().debug(
 5→    {
 6→      event,
 7→      ...(meta ?? {}),
 8→    },
 9→    message,
10→  );
11→}
12→
13→export function logInfo(event: string, message: string, meta?: Record<string, unknown>): void {
14→  getRequestLogger().info(
15→    {
16→      event,
17→      ...(meta ?? {}),
18→    },
19→    message,
20→  );
21→}
22→
23→export function logWarn(event: string, message: string, meta?: Record<string, unknown>): void {
24→  getRequestLogger().warn(
25→    {
26→      event,
27→      ...(meta ?? {}),
28→    },
29→    message,
30→  );
31→}
32→
33→export function logError(event: string, message: string, error: unknown, meta?: Record<string, unknown>): void {
34→  getRequestLogger().error(
35→    {
36→      event,
37→      ...(meta ?? {}),
38→      err: serializeError(error),
39→    },
40→    message,
41→  );
42→}
43→
44→export function elapsedMs(startedAt: number): number {
45→  return Number((performance.now() - startedAt).toFixed(2));
46→}
47→
48→export function userFacingError(error: unknown, fallback: string): string {
49→  if (!(error instanceof Error)) {
50→    return fallback;
51→  }
52→
53→  const causeMessage = extractCauseMessage(error);
54→  if (causeMessage && causeMessage !== error.message) {
55→    return `${error.message}: ${causeMessage}`;
56→  }
57→
58→  return error.message;
59→}
60→
61→function extractCauseMessage(error: Error & { cause?: unknown }): string | undefined {
62→  const cause = error.cause;
63→  if (!cause) {
64→    return undefined;
65→  }
66→
67→  if (cause instanceof Error) {
68→    return cause.message;
69→  }
70→
71→  if (typeof cause === "object" && cause !== null && "message" in cause) {
72→    const message = (cause as { message?: unknown }).message;
73→    if (typeof message === "string" && message.length > 0) {
74→      return message;
75→    }
76→  }
77→
78→  return undefined;
79→}
