 72→  }
 73→
 74→  if (!(error instanceof Error)) {
 75→    return error;
 76→  }
 77→
 78→  const candidate = error as Error & {
 79→    cause?: unknown;
 80→    statusCode?: unknown;
 81→    url?: unknown;
 82→    code?: unknown;
 83→    isRetryable?: unknown;
 84→    responseHeaders?: unknown;
 85→    responseBody?: unknown;
 86→    requestBodyValues?: unknown;
 87→    data?: unknown;
 88→  };
 89→
 90→  const serialized: Record<string, unknown> = {
 91→    name: candidate.name,
 92→    message: candidate.message,
 93→    stack: candidate.stack,
 94→  };
 95→
 96→  if (candidate.statusCode !== undefined) {
 97→    serialized.statusCode = candidate.statusCode;
 98→  }
 99→
100→  if (candidate.url !== undefined) {
101→    serialized.url = candidate.url;
102→  }
103→
104→  if (candidate.code !== undefined) {
105→    serialized.code = candidate.code;
106→  }
107→
108→  if (candidate.isRetryable !== undefined) {
109→    serialized.isRetryable = candidate.isRetryable;
110→  }
111→
112→  const requestBodySummary = summarizeRequestBodyValues(candidate.requestBodyValues);
113→  if (requestBodySummary !== undefined) {
114→    serialized.requestBodySummary = requestBodySummary;
115→  }
116→
117→  const responseHeaders = summarizeResponseHeaders(candidate.responseHeaders);
118→  if (responseHeaders !== undefined) {
119→    serialized.responseHeaders = responseHeaders;
120→  }
121→
122→  const responseBodySummary = summarizeResponseBody(candidate.responseBody);
123→  if (responseBodySummary !== undefined) {
