183→  }
184→
185→  if (Array.isArray(requestBodyValues.input)) {
186→    summary.inputCount = requestBodyValues.input.length;
187→  }
188→
189→  if (Array.isArray(requestBodyValues.tools)) {
190→    summary.toolsCount = requestBodyValues.tools.length;
191→  }
192→
193→  if (isRecord(requestBodyValues.response_format) && typeof requestBodyValues.response_format.type === "string") {
194→    summary.responseFormatType = requestBodyValues.response_format.type;
195→  }
196→
197→  const keys = Object.keys(summary);
198→  if (keys.length === 0) {
199→    summary.keys = Object.keys(requestBodyValues).slice(0, 20);
200→  }
201→
202→  return summary;
203→}
204→
205→function summarizeResponseHeaders(responseHeaders: unknown): Record<string, string> | undefined {
206→  if (responseHeaders instanceof Headers) {
207→    return selectResponseHeaders(Object.fromEntries(responseHeaders.entries()));
208→  }
209→
210→  if (isRecord(responseHeaders)) {
211→    const normalized: Record<string, string> = {};
212→    for (const [key, value] of Object.entries(responseHeaders)) {
213→      if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
214→        normalized[key] = String(value);
215→      }
216→    }
217→    return selectResponseHeaders(normalized);
218→  }
219→
220→  return undefined;
221→}
222→
223→function selectResponseHeaders(headers: Record<string, string>): Record<string, string> | undefined {
224→  const selected: Record<string, string> = {};
225→  const lowerMap = new Map<string, string>();
226→  for (const [key, value] of Object.entries(headers)) {
227→    lowerMap.set(key.toLowerCase(), value);
228→  }
229→
230→  const keys = [
231→    "content-type",
232→    "date",
233→    "server",
234→    "request-id",
235→    "x-request-id",
236→    "x-openrouter-request-id",
237→    "cf-ray",
238→  ];
239→
240→  for (const key of keys) {
241→    const value = lowerMap.get(key);
242→    if (value !== undefined) {
243→      selected[key] = truncateString(value, 300);
244→    }
245→  }
246→
247→  for (const [key, value] of lowerMap.entries()) {
248→    if (!key.startsWith("x-ratelimit")) {
249→      continue;
250→    }
251→    selected[key] = truncateString(value, 300);
252→  }
253→
254→  return Object.keys(selected).length > 0 ? selected : undefined;
255→}
256→
257→function summarizeResponseBody(responseBody: unknown): unknown {
258→  if (responseBody === undefined) {
259→    return undefined;
260→  }
261→
262→  if (typeof responseBody === "string") {
263→    const trimmed = responseBody.trim();
264→    if (trimmed.length === 0) {
265→      return "";
266→    }
267→
268→    try {
269→      const parsed = JSON.parse(trimmed) as unknown;
270→      return serializeUnknown(parsed);
271→    } catch {
272→      return truncateString(trimmed, 4000);
273→    }
274→  }
275→
276→  return serializeUnknown(responseBody);
277→}
278→
279→function extractProviderErrorDetails(payload: unknown): Record<string, unknown> | undefined {
280→  if (!isRecord(payload)) {
281→    return undefined;
282→  }
283→
284→  const errorObject = isRecord(payload.error) ? payload.error : payload;
285→  const details: Record<string, unknown> = {};
286→  const metadata = isRecord(errorObject.metadata) ? errorObject.metadata : undefined;
287→
288→  if (typeof errorObject.message === "string") {
289→    details.message = truncateString(errorObject.message, 1000);
290→  }
291→  if (typeof errorObject.type === "string") {
292→    details.type = errorObject.type;
293→  }
294→  if (typeof errorObject.code === "string" || typeof errorObject.code === "number") {
295→    details.code = errorObject.code;
296→  }
297→  if (typeof errorObject.param === "string") {
298→    details.param = errorObject.param;
299→  }
300→
301→  if (metadata) {
302→    if (typeof metadata.provider_name === "string") {
303→      details.providerName = metadata.provider_name;
304→    }
305→    if (typeof metadata.is_byok === "boolean") {
306→      details.isByok = metadata.is_byok;
307→    }
308→
309→    const upstream = extractUpstreamProviderError(metadata.raw);
310→    if (upstream !== undefined) {
311→      details.upstream = upstream;
312→      if (details.message === "Provider returned error" && typeof upstream.message === "string") {
313→        details.message = upstream.message;
314→      }
315→      if (details.type === undefined && typeof upstream.type === "string") {
316→        details.type = upstream.type;
317→      }
318→      if (details.code === undefined && (typeof upstream.code === "string" || typeof upstream.code === "number")) {
319→        details.code = upstream.code;
320→      }
321→      if (details.param === undefined && typeof upstream.param === "string") {
322→        details.param = upstream.param;
323→      }
324→    }
325→  }
326→
327→  return Object.keys(details).length > 0 ? details : undefined;
328→}
329→
330→function extractUpstreamProviderError(rawMetadata: unknown): Record<string, unknown> | undefined {
331→  if (typeof rawMetadata !== "string") {
332→    return undefined;
333→  }
334→
335→  const trimmed = rawMetadata.trim();
336→  if (trimmed.length === 0) {
337→    return undefined;
338→  }
339→
340→  try {
341→    const parsed = JSON.parse(trimmed) as unknown;
342→    if (!isRecord(parsed)) {
343→      return { raw: truncateString(trimmed, 2000) };
344→    }
345→
346→    const errorObject = isRecord(parsed.error) ? parsed.error : parsed;
347→    const details: Record<string, unknown> = {};
348→
349→    if (typeof errorObject.message === "string") {
350→      details.message = truncateString(errorObject.message, 1000);
351→    }
352→    if (typeof errorObject.type === "string") {
353→      details.type = errorObject.type;
354→    }
355→    if (typeof errorObject.code === "string" || typeof errorObject.code === "number") {
356→      details.code = errorObject.code;
357→    }
358→    if (typeof errorObject.param === "string") {
359→      details.param = errorObject.param;
360→    }
361→
362→    return Object.keys(details).length > 0 ? details : { raw: truncateString(trimmed, 2000) };
363→  } catch {
364→    return { raw: truncateString(trimmed, 2000) };
365→  }
366→}
367→
368→function serializeUnknown(value: unknown, depth = 0, seen = new Set<object>()): unknown {
369→  if (depth > 3) {
370→    return "[max depth reached]";
371→  }
372→
373→  if (value === null) {
374→    return "null";
375→  }
376→
377→  if (typeof value === "string") {
378→    return truncateString(value, 4000);
379→  }
380→
381→  if (typeof value === "number" || typeof value === "boolean" || value === undefined) {
382→    return value;
383→  }
384→
385→  if (value instanceof Date) {
386→    return value.toISOString();
387→  }
388→
389→  if (Array.isArray(value)) {
390→    return value.slice(0, 20).map((item) => serializeUnknown(item, depth + 1, seen));
391→  }
392→
393→  if (value instanceof Error) {
394→    return serializeError(value, depth + 1);
395→  }
396→
397→  if (!isRecord(value)) {
398→    return String(value);
399→  }
400→
401→  if (seen.has(value)) {
402→    return "[circular]";
403→  }
404→  seen.add(value);
405→
406→  const output: Record<string, unknown> = {};
407→  for (const [key, entryValue] of Object.entries(value).slice(0, 30)) {
408→    const normalizedKey = key.toLowerCase();
409→    if (normalizedKey === "user_id" || normalizedKey === "userid" || normalizedKey === "api_key" || normalizedKey === "apikey") {
410→      output[key] = "[redacted]";
411→      continue;
412→    }
413→    output[key] = serializeUnknown(entryValue, depth + 1, seen);
414→  }
415→  return output;
416→}
417→
418→function isRecord(value: unknown): value is Record<string, unknown> {
419→  return typeof value === "object" && value !== null;
420→}
421→
422→function truncateString(value: string, maxLength: number): string {
423→  if (value.length <= maxLength) {
424→    return value;
425→  }
426→  return `${value.slice(0, maxLength)}…[truncated]`;
427→}
