44→export function elapsedMs(startedAt: number): number {
45→  return Number((performance.now() - startedAt).toFixed(2));
46→}
47→
48→export function userFacingError(error: unknown, fallback: string): string {
49→  if (!(error instanceof Error)) {
50→    return fallback;
51→  }
52→
53→  const causeMessage = extractCauseMessage(error);
54→  if (causeMessage && causeMessage !== error.message) {
55→    return `${error.message}: ${causeMessage}`;
56→  }
57→
58→  return error.message;
59→}
60→
61→function extractCauseMessage(error: Error & { cause?: unknown }): string | undefined {
62→  const cause = error.cause;
63→  if (!cause) {
64→    return undefined;
65→  }
66→
67→  if (cause instanceof Error) {
68→    return cause.message;
69→  }
70→
71→  if (typeof cause === "object" && cause !== null && "message" in cause) {
72→    const message = (cause as { message?: unknown }).message;
73→    if (typeof message === "string" && message.length > 0) {
74→      return message;
75→    }
76→  }
77→
78→  return undefined;
79→}
