 42→export function loadServerConfig(): ServerConfig {
 43→  const inferenceProvider = parseInferenceProvider();
 44→
 45→  const openRouterApiKey = inferenceProvider === "openrouter"
 46→    ? requireEnv("OPENROUTER_API_KEY")
 47→    : Bun.env.OPENROUTER_API_KEY?.trim() || undefined;
 48→
 49→  const ollamaBaseUrl = inferenceProvider === "ollama"
 50→    ? (Bun.env.OLLAMA_BASE_URL?.trim() || "http://127.0.0.1:11434")
 51→    : undefined;
 52→
 53→  const extractionStoreThreshold = parseUnitInterval(
 54→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 55→    "EXTRACTION_STORE_THRESHOLD",
 56→  );
 57→
 58→  const extractionDisplayThreshold = parseUnitInterval(
 59→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 60→    "EXTRACTION_DISPLAY_THRESHOLD",
 61→  );
 62→
 63→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 64→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 65→  }
 66→
 67→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 68→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 69→  const pmAgentModelId = optionalEnv("PM_AGENT_MODEL") ?? extractionModelId;
 70→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 71→  const embeddingModelId = requireEnv("EMBEDDING_MODEL");
 72→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 73→
 74→  const surrealUrl = requireEnv("SURREAL_URL");
 75→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 76→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 77→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 78→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 79→
 80→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 81→  const observerModelId = optionalEnv("OBSERVER_MODEL") ?? extractionModelId;
 82→  const scorerModelId = optionalEnv("SCORER_MODEL") ?? extractionModelId;
 83→  const githubWebhookSecret = optionalEnv("GITHUB_WEBHOOK_SECRET");
 84→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 85→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 86→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 87→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 88→  const anthropicApiUrl = optionalEnv("ANTHROPIC_API_URL") ?? "https://api.anthropic.com";
 89→  const anthropicApiKey = optionalEnv("ANTHROPIC_API_KEY");
 90→
 91→  const openRouterReasoning = inferenceProvider === "openrouter"
 92→    ? parseOpenRouterReasoning()
 93→    : undefined;
 94→
 95→  return {
 96→    inferenceProvider,
 97→    ...(openRouterApiKey ? { openRouterApiKey } : {}),
 98→    ...(ollamaBaseUrl ? { ollamaBaseUrl } : {}),
 99→    chatAgentModelId,
100→    extractionModelId,
101→    pmAgentModelId,
102→    analyticsAgentModelId,
103→    embeddingModelId,
104→    embeddingDimension,
105→    extractionStoreThreshold,
106→    extractionDisplayThreshold,
107→    ...(openRouterReasoning ? { openRouterReasoning } : {}),
108→    surrealUrl,
109→    surrealUsername,
110→    surrealPassword,
111→    surrealNamespace,
112→    surrealDatabase,
113→    port,
114→    observerModelId,
115→    scorerModelId,
116→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
117→    betterAuthSecret,
118→    betterAuthUrl,
119→    githubClientId,
120→    githubClientSecret,
121→    anthropicApiUrl,
122→    ...(anthropicApiKey ? { anthropicApiKey } : {}),
123→  };
124→}
