126→function optionalEnv(name: string): string | undefined {
127→  const value = Bun.env[name]?.trim();
128→  if (!value || value.length === 0) return undefined;
129→  return value;
130→}
131→
132→function requireEnv(name: string): string {
133→  const value = Bun.env[name];
134→  if (!value || value.trim().length === 0) {
135→    throw new Error(`${name} is required`);
136→  }
137→
138→  return value;
139→}
140→
141→function parsePositiveInteger(value: string, envName: string): number {
142→  const parsed = Number(value);
143→  if (!Number.isInteger(parsed) || parsed < 1) {
144→    throw new Error(`${envName} must be a positive integer`);
145→  }
146→  return parsed;
147→}
148→
149→function parseUnitInterval(value: string, envName: string): number {
150→  const parsed = Number(value);
151→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
152→    throw new Error(`${envName} must be a number between 0 and 1`);
153→  }
154→
155→  return parsed;
156→}
157→
158→function parseInferenceProvider(): InferenceProvider {
159→  const value = Bun.env.INFERENCE_PROVIDER?.trim().toLowerCase();
160→  if (!value || value === "openrouter") return "openrouter";
161→  if (value === "ollama") return "ollama";
162→  throw new Error("INFERENCE_PROVIDER must be one of: openrouter, ollama");
163→}
164→
165→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
166→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
167→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
168→
169→  if (!effortValue && !maxTokensValue) {
170→    return undefined;
171→  }
172→
173→  const reasoning: OpenRouterReasoningOptions = {};
174→
175→  if (effortValue) {
176→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
177→
178→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
179→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
180→    }
181→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
182→  }
183→
184→  if (maxTokensValue) {
185→    const parsed = Number(maxTokensValue);
186→    if (!Number.isFinite(parsed) || parsed < 1) {
187→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
188→    }
189→    reasoning.max_tokens = parsed;
190→  }
191→
192→  return reasoning;
193→}
